1	// Types
2	
3	export interface Customer {
4	  yearsWithMHPCO: number;
5	}
6	
7	export interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	export interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	export interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	export interface Incident {
25	  cause: string;
26	  damages: Damage[];
27	}
28	
29	export interface ClaimStep {
30	  op: "claim";
31	  policy: number;
32	  incident: Incident;
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: Customer;
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface Output {
54	  results: StepResult[];
55	}
56	
57	// Item catalogue
58	
59	const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
60	  sword: { insuranceValue: 1000, basePremium: 100 },
61	  amulet: { insuranceValue: 600, basePremium: 60 },
62	  staff: { insuranceValue: 800, basePremium: 80 },
63	  potion: { insuranceValue: 400, basePremium: 40 },
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const COMPONENT_VALUE = 250;
68	const COMPONENT_PREMIUM = 25;
69	const BLOCK_PREMIUM = 60;
70	
71	function isComponent(type: string): boolean {
72	  return COMPONENT_TYPES.has(type);
73	}
74	
75	function isKnownType(type: string): boolean {
76	  return type in MAIN_ITEMS || isComponent(type);
77	}
78	
79	function itemInsuranceValue(item: Item): number {
80	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].insuranceValue;
81	  if (isComponent(item.type)) return COMPONENT_VALUE;
82	  throw new Error(`Unknown item type: ${item.type}`);
83	}
84	
85	// Premium calc
86	
87	function itemBasePremium(item: Item): number {
88	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].basePremium;
89	  if (isComponent(item.type)) return COMPONENT_PREMIUM;
90	  throw new Error(`Unknown item type: ${item.type}`);
91	}
92	
93	function componentsBasePremium(items: Item[]): number {
94	  // Group components by type. For each group, count blocks of 3 → 60, plus singles.
95	  const counts: Record<string, number> = {};
96	  for (const item of items) {
97	    if (isComponent(item.type)) {
98	      counts[item.type] = (counts[item.type] ?? 0) + 1;
99	    }
100	  }
101	  let total = 0;
102	  for (const type of Object.keys(counts)) {
103	    const count = counts[type];
104	    const blocks = Math.floor(count / 3);
105	    const remainder = count % 3;
106	    // Block applies only when group is exactly 3 alike? Spec says "block of 3 alike" at 60G special.
107	    // Examples: 3 runes → 60; 4 runes → 100 (no block - block requires exactly 3); 7 runes → 175.
108	    // 7 runes = 175 = 7 * 25, so blocks don't apply when group is not exactly 3.
109	    // 6 runes? Not specified. Let me re-read.
110	    // "A building block of 3 alike components is offered at a special base premium of 60 G."
111	    // 4 runes → 100 G (no block — block requires exactly 3)
112	    // So block requires the count to be exactly 3.
113	    if (count === 3) {
114	      total += BLOCK_PREMIUM;
115	    } else {
116	      total += count * COMPONENT_PREMIUM;
117	    }
118	    // suppress unused
119	    void blocks;
120	    void remainder;
121	  }
122	  return total;
123	}
124	
125	function isHighEnchantment(item: Item): boolean {
126	  return (item.enchantment ?? 0) >= 5;
127	}
128	
129	function itemBasePremiumWithItemModifiers(item: Item): number {
130	  const base = itemBasePremium(item);
131	  let extra = 0;
132	  if (item.cursed) extra += base * 0.5;
133	  if (isHighEnchantment(item)) extra += base * 0.3;
134	  return base + extra;
135	}
136	
137	// Multi-item examples scoping:
138	// Cursed sword (100) + plain amulet (60) → policy base premium 160; cursed adds 50 (50% of cursed sword's base) → 210
139	// So policy base premium = sum of base premiums, then per-item surcharges added to the policy total.
140	// We compute: sum of (per item: base + item-modifiers) = policy "modified" sum, then apply policy-wide.
141	
142	interface CustomerContext {
143	  yearsWithMHPCO: number;
144	  contractIndex: number; // 0 = first contract, 1+ = follow-up
145	}
146	
147	function quotePremium(items: Item[], ctx: CustomerContext): number {
148	  // Validate items
149	  for (const item of items) {
150	    if (!isKnownType(item.type)) {
151	      throw new Error(`Unknown item type: ${item.type}`);
152	    }
153	  }
154	
155	  // Components: grouped block discount applies to base premium for those groups.
156	  // Per-item modifiers apply to base premium; but components have no enchantment/cursed in examples.
157	  // We'll apply per-item modifiers to components individually based on their own base premium (25 G).
158	  // But the block: when block applies (exactly 3), each rune's effective base premium is 20.
159	  // Examples don't cover cursed runes, so we keep it simple: compute base premiums per component group
160	  // (with block discount), and main items individually with per-item modifiers.
161	
162	  let policyBase = 0;
163	  let itemModifierSurcharges = 0;
164	
165	  // Main items
166	  for (const item of items) {
167	    if (item.type in MAIN_ITEMS) {
168	      const base = itemBasePremium(item);
169	      policyBase += base;
170	      if (item.cursed) itemModifierSurcharges += base * 0.5;
171	      if (isHighEnchantment(item)) itemModifierSurcharges += base * 0.3;
172	    }
173	  }
174	
175	  // Components: apply group base premium (with block discount)
176	  // For per-item modifiers on components: spec doesn't cover; we apply per-item modifiers using
177	  // each component's effective base (with block split equally across 3).
178	  const componentGroups: Record<string, Item[]> = {};
179	  for (const item of items) {
180	    if (isComponent(item.type)) {
181	      if (!componentGroups[item.type]) componentGroups[item.type] = [];
182	      componentGroups[item.type].push(item);
183	    }
184	  }
185	  for (const type of Object.keys(componentGroups)) {
186	    const group = componentGroups[type];
187	    let groupBase: number;
188	    let perItemBase: number;
189	    if (group.length === 3) {
190	      groupBase = BLOCK_PREMIUM;
191	      perItemBase = BLOCK_PREMIUM / 3;
192	    } else {
193	      groupBase = group.length * COMPONENT_PREMIUM;
194	      perItemBase = COMPONENT_PREMIUM;
195	    }
196	    policyBase += groupBase;
197	    for (const comp of group) {
198	      if (comp.cursed) itemModifierSurcharges += perItemBase * 0.5;
199	      if (isHighEnchantment(comp)) itemModifierSurcharges += perItemBase * 0.3;
200	    }
201	  }
202	
203	  let premium = policyBase + itemModifierSurcharges;
204	
205	  // Policy-wide modifiers, applied to policy base (sum of item base premiums)
206	  if (ctx.yearsWithMHPCO >= 2) {
207	    premium -= policyBase * 0.2; // loyalty discount
208	  }
209	
210	  // First insurance: each item in a quote treated as first insurance → 10% on each item's base
211	  // Per integration example #2: "+10 G first insurance" on a 100 G sword. So 10% of item base.
212	  // Applied per item.
213	  for (const item of items) {
214	    if (item.type in MAIN_ITEMS) {
215	      premium += itemBasePremium(item) * 0.1;
216	    }
217	  }
218	  for (const type of Object.keys(componentGroups)) {
219	    const group = componentGroups[type];
220	    const perItemBase = group.length === 3 ? BLOCK_PREMIUM / 3 : COMPONENT_PREMIUM;
221	    premium += group.length * perItemBase * 0.1;
222	  }
223	
224	  // Follow-up contract discount: 15% on each contract after first → applied to policy base
225	  if (ctx.contractIndex >= 1) {
226	    premium -= policyBase * 0.15;
227	  }
228	
229	  // Processing fee
230	  premium += 5;
231	
232	  // Round up (in MHPCO's favor for premiums)
233	  return Math.ceil(premium);
234	}
235	
236	// Policy state for claims
237	
238	interface Policy {
239	  items: Item[];
240	  insuranceSum: number;
241	  cap: number;
242	  remainingCap: number;
243	}
244	
245	function createPolicy(items: Item[]): Policy {
246	  let insuranceSum = 0;
247	  for (const item of items) {
248	    insuranceSum += itemInsuranceValue(item);
249	  }
250	  const cap = insuranceSum * 2;
251	  return {
252	    items: [...items],
253	    insuranceSum,
254	    cap,
255	    remainingCap: cap,
256	  };
257	}
258	
259	function findMatchingItem(policy: Policy, itemType: string, usedIndices: Set<number>): Item | undefined {
260	  for (let i = 0; i < policy.items.length; i++) {
261	    if (!usedIndices.has(i) && policy.items[i].type === itemType) {
262	      usedIndices.add(i);
263	      return policy.items[i];
264	    }
265	  }
266	  return undefined;
267	}
268	
269	function damagePayout(item: Item, damageAmount: number): number {
270	  let reimbursement: number;
271	  const enchantment = item.enchantment ?? 0;
272	  const material = item.material;
273	  // dragon material → fully reimbursed; high enchantment ≥8 → 50%
274	  // If both apply, the 50% rule wins (per spec example).
275	  if (enchantment >= 8) {
276	    reimbursement = damageAmount * 0.5;
277	  } else if (material === "dragon") {
278	    reimbursement = damageAmount;
279	  } else {
280	    reimbursement = damageAmount;
281	  }
282	  const afterDeductible = reimbursement - 100;
283	  return Math.max(0, afterDeductible);
284	}
285	
286	function processClaim(policy: Policy, incident: Incident): ClaimResult {
287	  // Validate: all damages must reference items in the policy
288	  if (!isKnownType("sword")) {
289	    /* no-op */
290	  }
291	  for (const d of incident.damages) {
292	    if (d.amount < 0) {
293	      throw new Error(`Negative damage amount: ${d.amount}`);
294	    }
295	    if (!isKnownType(d.itemType)) {
296	      throw new Error(`Unknown item type in damage: ${d.itemType}`);
297	    }
298	  }
299	
300	  // Ensure damages can be matched 1:1 to distinct items in the policy
301	  const usedIndices = new Set<number>();
302	  const matched: { item: Item; damage: Damage }[] = [];
303	  for (const d of incident.damages) {
304	    const item = findMatchingItem(policy, d.itemType, usedIndices);
305	    if (!item) {
306	      throw new Error(`Damage references item not in policy: ${d.itemType}`);
307	    }
308	    matched.push({ item, damage: d });
309	  }
310	
