// Types

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface Output {
  results: StepResult[];
}

// Item catalogue

const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || isComponent(type);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].insuranceValue;
  if (isComponent(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

// Premium calc

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].basePremium;
  if (isComponent(item.type)) return COMPONENT_PREMIUM;
  throw new Error(`Unknown item type: ${item.type}`);
}

function componentsBasePremium(items: Item[]): number {
  // Group components by type. For each group, count blocks of 3 → 60, plus singles.
  const counts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      counts[item.type] = (counts[item.type] ?? 0) + 1;
    }
  }
  let total = 0;
  for (const type of Object.keys(counts)) {
    const count = counts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    // Block applies only when group is exactly 3 alike? Spec says "block of 3 alike" at 60G special.
    // Examples: 3 runes → 60; 4 runes → 100 (no block - block requires exactly 3); 7 runes → 175.
    // 7 runes = 175 = 7 * 25, so blocks don't apply when group is not exactly 3.
    // 6 runes? Not specified. Let me re-read.
    // "A building block of 3 alike components is offered at a special base premium of 60 G."
    // 4 runes → 100 G (no block — block requires exactly 3)
    // So block requires the count to be exactly 3.
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * COMPONENT_PREMIUM;
    }
    // suppress unused
    void blocks;
    void remainder;
  }
  return total;
}

function isHighEnchantment(item: Item): boolean {
  return (item.enchantment ?? 0) >= 5;
}

function itemBasePremiumWithItemModifiers(item: Item): number {
  const base = itemBasePremium(item);
  let extra = 0;
  if (item.cursed) extra += base * 0.5;
  if (isHighEnchantment(item)) extra += base * 0.3;
  return base + extra;
}

// Multi-item examples scoping:
// Cursed sword (100) + plain amulet (60) → policy base premium 160; cursed adds 50 (50% of cursed sword's base) → 210
// So policy base premium = sum of base premiums, then per-item surcharges added to the policy total.
// We compute: sum of (per item: base + item-modifiers) = policy "modified" sum, then apply policy-wide.

interface CustomerContext {
  yearsWithMHPCO: number;
  contractIndex: number; // 0 = first contract, 1+ = follow-up
}

function quotePremium(items: Item[], ctx: CustomerContext): number {
  // Validate items
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  // Components: grouped block discount applies to base premium for those groups.
  // Per-item modifiers apply to base premium; but components have no enchantment/cursed in examples.
  // We'll apply per-item modifiers to components individually based on their own base premium (25 G).
  // But the block: when block applies (exactly 3), each rune's effective base premium is 20.
  // Examples don't cover cursed runes, so we keep it simple: compute base premiums per component group
  // (with block discount), and main items individually with per-item modifiers.

  let policyBase = 0;
  let itemModifierSurcharges = 0;

  // Main items
  for (const item of items) {
    if (item.type in MAIN_ITEMS) {
      const base = itemBasePremium(item);
      policyBase += base;
      if (item.cursed) itemModifierSurcharges += base * 0.5;
      if (isHighEnchantment(item)) itemModifierSurcharges += base * 0.3;
    }
  }

  // Components: apply group base premium (with block discount)
  // For per-item modifiers on components: spec doesn't cover; we apply per-item modifiers using
  // each component's effective base (with block split equally across 3).
  const componentGroups: Record<string, Item[]> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      if (!componentGroups[item.type]) componentGroups[item.type] = [];
      componentGroups[item.type].push(item);
    }
  }
  for (const type of Object.keys(componentGroups)) {
    const group = componentGroups[type];
    let groupBase: number;
    let perItemBase: number;
    if (group.length === 3) {
      groupBase = BLOCK_PREMIUM;
      perItemBase = BLOCK_PREMIUM / 3;
    } else {
      groupBase = group.length * COMPONENT_PREMIUM;
      perItemBase = COMPONENT_PREMIUM;
    }
    policyBase += groupBase;
    for (const comp of group) {
      if (comp.cursed) itemModifierSurcharges += perItemBase * 0.5;
      if (isHighEnchantment(comp)) itemModifierSurcharges += perItemBase * 0.3;
    }
  }

  let premium = policyBase + itemModifierSurcharges;

  // Policy-wide modifiers, applied to policy base (sum of item base premiums)
  if (ctx.yearsWithMHPCO >= 2) {
    premium -= policyBase * 0.2; // loyalty discount
  }

  // First insurance: each item in a quote treated as first insurance → 10% on each item's base
  // Per integration example #2: "+10 G first insurance" on a 100 G sword. So 10% of item base.
  // Applied per item.
  for (const item of items) {
    if (item.type in MAIN_ITEMS) {
      premium += itemBasePremium(item) * 0.1;
    }
  }
  for (const type of Object.keys(componentGroups)) {
    const group = componentGroups[type];
    const perItemBase = group.length === 3 ? BLOCK_PREMIUM / 3 : COMPONENT_PREMIUM;
    premium += group.length * perItemBase * 0.1;
  }

  // Follow-up contract discount: 15% on each contract after first → applied to policy base
  if (ctx.contractIndex >= 1) {
    premium -= policyBase * 0.15;
  }

  // Processing fee
  premium += 5;

  // Round up (in MHPCO's favor for premiums)
  return Math.ceil(premium);
}

// Policy state for claims

interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

function createPolicy(items: Item[]): Policy {
  let insuranceSum = 0;
  for (const item of items) {
    insuranceSum += itemInsuranceValue(item);
  }
  const cap = insuranceSum * 2;
  return {
    items: [...items],
    insuranceSum,
    cap,
    remainingCap: cap,
  };
}

function findMatchingItem(policy: Policy, itemType: string, usedIndices: Set<number>): Item | undefined {
  for (let i = 0; i < policy.items.length; i++) {
    if (!usedIndices.has(i) && policy.items[i].type === itemType) {
      usedIndices.add(i);
      return policy.items[i];
    }
  }
  return undefined;
}

function damagePayout(item: Item, damageAmount: number): number {
  let reimbursement: number;
  const enchantment = item.enchantment ?? 0;
  const material = item.material;
  // dragon material → fully reimbursed; high enchantment ≥8 → 50%
  // If both apply, the 50% rule wins (per spec example).
  if (enchantment >= 8) {
    reimbursement = damageAmount * 0.5;
  } else if (material === "dragon") {
    reimbursement = damageAmount;
  } else {
    reimbursement = damageAmount;
  }
  const afterDeductible = reimbursement - 100;
  return Math.max(0, afterDeductible);
}

function processClaim(policy: Policy, incident: Incident): ClaimResult {
  // Validate: all damages must reference items in the policy
  if (!isKnownType("sword")) {
    /* no-op */
  }
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    if (!isKnownType(d.itemType)) {
      throw new Error(`Unknown item type in damage: ${d.itemType}`);
    }
  }

  // Ensure damages can be matched 1:1 to distinct items in the policy
  const usedIndices = new Set<number>();
  const matched: { item: Item; damage: Damage }[] = [];
  for (const d of incident.damages) {
    const item = findMatchingItem(policy, d.itemType, usedIndices);
    if (!item) {
      throw new Error(`Damage references item not in policy: ${d.itemType}`);
    }
    matched.push({ item, damage: d });
  }

  let totalPayoutFraction = 0;
  for (const { item, damage } of matched) {
    totalPayoutFraction += damagePayout(item, damage.amount);
  }

  // Apply cap. Cap remaining tracked in integer G; payout rounded down.
  // Spec rounds final payout down; but cap operates on integers (examples use integer amounts).
  // Round payout first to integer (in MHPCO's favor → down), then cap.
  const desiredPayout = Math.floor(totalPayoutFraction);
  const cappedPayout = Math.min(desiredPayout, policy.remainingCap);
  policy.remainingCap -= cappedPayout;
  return {
    payout: cappedPayout,
    remainingCap: policy.remainingCap,
  };
}

// Main entry

export function processScenario(scenario: Scenario): Output {
  const results: StepResult[] = [];
  const policies: Record<number, Policy> = {};
  let contractIndex = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const ctx: CustomerContext = {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        contractIndex,
      };
      const premium = quotePremium(step.items, ctx);
      results.push({ premium });
      policies[i] = createPolicy(step.items);
      contractIndex++;
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const result = processClaim(policy, step.incident);
      results.push(result);
    } else {
      throw new Error(`Unknown op: ${(step as any).op}`);
    }
  }

  return { results };
}

